<template><el-card v-if="d"><template #header><div class="head"><b>敏感导出申请详情</b><el-button v-if="d.executable&&user.hasPermission('data:export:sensitive:execute')" type="danger" @click="run">执行导出</el-button></div></template><el-descriptions border><el-descriptions-item label="申请编号">{{d.application.applicationNo}}</el-descriptions-item><el-descriptions-item label="申请状态">{{d.application.status}}</el-descriptions-item><el-descriptions-item label="模块">{{d.professional.exportModule}}</el-descriptions-item><el-descriptions-item label="字段">{{d.professional.requestedFields}}</el-descriptions-item><el-descriptions-item label="条件摘要">{{d.professional.filterSnapshot}}</el-descriptions-item><el-descriptions-item label="批准上限">{{d.professional.expectedRowLimit}}</el-descriptions-item></el-descriptions><el-alert class="tip" title="材料、提交、撤回和审批请使用通用申请及审批中心。" type="info"/></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage}from'element-plus';import{useUserStore}from'../../stores/user';import{getExportApplication,executeSensitive}from'../../api/exports';const route=useRoute(),router=useRouter(),user=useUserStore(),d=ref();async function load(){d.value=await getExportApplication(route.params.id)}async function run(){const x=await executeSensitive(route.params.id,d.value.professional.version);ElMessage.success('敏感导出已生成');router.push('/exports/'+x.exportLogId)}onMounted(load)</script><style scoped>.head{display:flex;justify-content:space-between}.tip{margin-top:16px}</style>
